module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);

	reg [7:0] cnt;
	reg [1:0] state;
	reg p_red, p_yellow, p_green;


	always @(posedge clk ,negedge rst_n) begin

		if(rst_n==0) begin 
			p_red <= 0;
			p_yellow <= 0;
			p_green <= 0;
			state <= idle ;

		end else begin 

		case(state)

		idle : begin 
			p_red <= 0;
			p_yellow <= 0;
			p_green <= 0;
			state <= s1_red;

			end

			s1_red : begin
				p_red <= 1;
				p_yellow <= 0;
				p_green <= 0;

				if( cnt == 3 )begin
					state <= s3_green;

				end else begin 
						state <= s1_red;

					end

			end

			s2_yellow : begin 
				p_red <= 0;
				p_yellow <= 1;
				p_green <= 0;

				if( cnt == 3 )begin
					state <= s1_red;

				end else begin 
						state <= s2_yellow;

					end

			end

			s3_green : begin
				p_red <= 0;
				p_yellow <= 0;
				p_green <= 1;

				if( cnt == 3 )begin
					state <= s2_yellow;

				end else begin 
						state <= s3_green;

					end

			end

		endcase	

		end

	end	

	always@( posedge clk ,negedge rst_n)begin 

		if( !rst_n )
			cnt <= 10 ;
		else begin 	

			if( pass_request && green && (cnt > 10))
				cnt <= 10;
			else if( !green && p_green )
				cnt <= 60;
			else if( !yellow && p_yellow )
				cnt <= 5;
			else if( !red && p_red) cnt <= 10; else cnt <= cnt - 1;
		end

	end

	assign clock = cnt;

	always@(posedge clk ,negedge rst_n)begin 

		if( !rst_n)begin
			red <= 0;
			yellow <= 0;
			green <= 0;

		end else begin 

			red <= p_red;
			yellow <= p_yellow;
			green <= p_green;

		end

	end

endmodule
